  "inlineSchema": "// Document Tracking & Workflow Automation System\n// Data model: departments, users, documents, multi-department routing,\n// audit trail, reference number sequencing, and notifications.\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"./node_modules/@prisma/client\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nenum Role {\n  REGISTRY_STAFF // uploads/registers incoming documents\n  GM // General Manager — always the first stop after registration\n  DEPARTMENT_USER // works within an assigned department\n  DEPARTMENT_HEAD\n  ADMIN // manages departments, users, and sees everything\n}\n\nenum DocumentStatus {\n  PENDING // registered, not yet opened by any department\n  IN_PROGRESS // opened / actively being handled by at least one department\n  COMPLETED // all routes marked complete\n  ARCHIVED\n}\n\nenum RouteStatus {\n  PENDING // sitting in this department's inbox, not yet opened\n  OPENED\n  FORWARDED // forwarded onward — this hop is now historical\n  COMPLETED // this hop is where the document's journey ended\n}\n\nenum NotificationChannel {\n  IN_APP\n  EMAIL\n}\n\nenum NotificationStatus {\n  PENDING\n  SENT\n  FAILED\n}\n\nmodel Department {\n  id         String   @id @default(cuid())\n  name       String   @unique\n  code       String   @unique // short code used in reference numbers, e.g. \"IT\", \"FIN\"\n  isGmOffice Boolean  @default(false) // exactly one department should be flagged true — the GM's office, the mandatory first stop\n  createdAt  DateTime @default(now())\n\n  users            User[]\n  documentsCreated Document[]          @relation(\"DocumentsCreatedByDept\")\n  routesFrom       DocumentRoute[]     @relation(\"RouteFromDept\")\n  routesTo         DocumentRoute[]     @relation(\"RouteToDept\")\n  sequences        ReferenceSequence[]\n\n  @@map(\"departments\")\n}\n\nmodel User {\n  id           String      @id @default(cuid())\n  // Mirrors the Supabase Auth user id (auth.users.id) — Supabase handles\n  // credential storage; this table holds app-level profile + role data.\n  authId       String      @unique\n  fullName     String\n  email        String      @unique\n  role         Role        @default(DEPARTMENT_USER)\n  departmentId String?\n  department   Department? @relation(fields: [departmentId], references: [id])\n  isActive     Boolean     @default(true)\n  createdAt    DateTime    @default(now())\n\n  documentsRegistered Document[]      @relation(\"RegisteredBy\")\n  routesAssigned      DocumentRoute[] @relation(\"AssignedTo\")\n  routeActions        RouteAction[]\n  notifications       Notification[]\n\n  @@index([departmentId])\n  @@map(\"users\")\n}\n\n// One row per calendar year per institution (or per dept, if you want\n// per-department numbering) — guarantees gapless, race-safe sequencing\n// via a single atomic UPDATE ... RETURNING in the application layer.\nmodel ReferenceSequence {\n  id           String      @id @default(cuid())\n  year         Int\n  departmentId String? // null = institution-wide sequence\n  department   Department? @relation(fields: [departmentId], references: [id])\n  lastValue    Int         @default(0)\n\n  @@unique([year, departmentId])\n  @@map(\"reference_sequences\")\n}\n\nmodel Document {\n  id               String         @id @default(cuid())\n  referenceNumber  String         @unique // e.g. TAF/IN/2026/001\n  senderName       String\n  senderOrg        String?\n  subject          String\n  receivedDate     DateTime\n  scannedFilePath  String // path within Supabase Storage bucket\n  fileSizeBytes    Int?\n  originalFileName String?\n  status           DocumentStatus @default(PENDING)\n\n  registeredById String\n  registeredBy   User       @relation(\"RegisteredBy\", fields: [registeredById], references: [id])\n  originDeptId   String\n  originDept     Department @relation(\"DocumentsCreatedByDept\", fields: [originDeptId], references: [id])\n\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n  completedAt DateTime?\n\n  routes      DocumentRoute[]\n  auditEvents AuditEvent[]\n\n  @@index([status])\n  @@index([senderName])\n  @@map(\"documents\")\n}\n\n// One row per hop in the document's journey: Registry -> GM -> Dept A ->\n// Dept B -> ... Exactly one route per document should be \"active\"\n// (status PENDING or OPENED) at any time — that row is the document's\n// current location. All earlier rows are historical (FORWARDED/COMPLETED).\nmodel DocumentRoute {\n  id         String   @id @default(cuid())\n  documentId String\n  document   Document @relation(fields: [documentId], references: [id], onDelete: Cascade)\n  sequence   Int // 1 = first hop (GM), 2 = second hop, etc.\n\n  fromDeptId String?\n  fromDept   Department? @relation(\"RouteFromDept\", fields: [fromDeptId], references: [id])\n  toDeptId   String\n  toDept     Department  @relation(\"RouteToDept\", fields: [toDeptId], references: [id])\n\n  status         RouteStatus @default(PENDING)\n  assignedUserId String?\n  assignedUser   User?       @relation(\"AssignedTo\", fields: [assignedUserId], references: [id])\n  comments       String?\n\n  receivedAt  DateTime  @default(now())\n  openedAt    DateTime?\n  completedAt DateTime?\n  updatedAt   DateTime  @updatedAt\n\n  actions       RouteAction[]\n  notifications Notification[]\n\n  @@unique([documentId, sequence])\n  @@index([toDeptId, status])\n  @@index([documentId])\n  @@map(\"document_routes\")\n}\n\n// Granular per-hop history — supports forwarding, comments, completion.\nmodel RouteAction {\n  id        String        @id @default(cuid())\n  routeId   String\n  route     DocumentRoute @relation(fields: [routeId], references: [id], onDelete: Cascade)\n  userId    String\n  user      User          @relation(fields: [userId], references: [id])\n  action    String // \"OPENED\" | \"COMMENTED\" | \"FORWARDED\" | \"COMPLETED\"\n  note      String?\n  createdAt DateTime      @default(now())\n\n  @@map(\"route_actions\")\n}\n\n// Top-level, document-wide audit trail (visible to Registry) — separate\n// from per-route actions so Registry gets one clean timeline per document.\nmodel AuditEvent {\n  id         String   @id @default(cuid())\n  documentId String\n  document   Document @relation(fields: [documentId], references: [id], onDelete: Cascade)\n  actorName  String\n  event      String // e.g. \"REGISTERED\", \"ROUTED_TO_IT\", \"COMPLETED_BY_FINANCE\"\n  detail     String?\n  createdAt  DateTime @default(now())\n\n  @@index([documentId])\n  @@map(\"audit_events\")\n}\n\nmodel Notification {\n  id        String              @id @default(cuid())\n  userId    String\n  user      User                @relation(fields: [userId], references: [id])\n  routeId   String?\n  route     DocumentRoute?      @relation(fields: [routeId], references: [id])\n  channel   NotificationChannel\n  status    NotificationStatus  @default(PENDING)\n  title     String\n  body      String\n  readAt    DateTime?\n  createdAt DateTime            @default(now())\n\n  @@index([userId, readAt])\n  @@map(\"notifications\")\n}\n"
